/**
 * Get language name by code
 */
export function getLanguageName(code: string, lang: 'en' | 'ru' = 'en'): string {
  const language = LANGUAGES[code.toUpperCase()];
  return language ? language[lang] : LANGUAGES['@empty'][lang];
}

/**
 * Check if language code is valid
 */
export function isValidLanguageCode(code: string): boolean {
  return code.toUpperCase() in LANGUAGES && code.toUpperCase() !== '@EMPTY';
}

/**
 * Get all language codes
 */
export function getLanguageCodes(): string[] {
  return Object.keys(LANGUAGES).filter(code => code !== '@empty');
}
