/**
 * Get country name by code
 */
export function getCountryName(code: string, lang: 'en' | 'ru' = 'en'): string {
  const country = COUNTRIES[code.toUpperCase()];
  return country ? country[lang] : COUNTRIES['@empty'][lang];
}

/**
 * Check if country code is valid
 */
export function isValidCountryCode(code: string): boolean {
  return code.toUpperCase() in COUNTRIES && code.toUpperCase() !== '@EMPTY';
}

/**
 * Get all country codes
 */
export function getCountryCodes(): string[] {
  return Object.keys(COUNTRIES).filter(code => code !== '@empty');
}
